/** Brand wordmark — simple text rendering. */
export function HelixLogoTextIcon({ width = 88, height = 38, className }: { width?: number; height?: number; className?: string }) {
  return (
    <span
      style={{ width, height, lineHeight: `${height}px` }}
      className={className}
    >
      <span className="select-none font-serif text-[var(--logo-color)] text-[20px] tracking-tight">
        Helix
      </span>
    </span>
  )
}

export function HelixTextIcon({ size = 24, className }: { size?: number; className?: string }) {
  return (
    <span
      style={{ fontSize: size }}
      className={`select-none font-serif text-[var(--text-primary)] tracking-tight leading-none ${className ?? ''}`}
    >
      Helix
    </span>
  )
}
